    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long x;
        int cnt0=0,cnt1=0,cntm1=0,cntBig=0;
        for(int i=0;i<N;i++){
            scanf("%lld",&x);
            if(x==0) cnt0++;
            else if(x==1) cnt1++;
            else if(x==-1) cntm1++;
            else cntBig++;
        }
        int ok=1;
        if(cntBig>1) ok=0;
        else if(cntBig==1 && cntm1>0) ok=0;
        else if(cntm1>1 && cnt1==0) ok=0;
        printf("%d\n",ok);
    }
    return 0;
}

