import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int cnt0 = 0, cnt1 = 0, cntm1 = 0, cntBig = 0;
            for (int i = 0; i < N; i++) {
                long x = fs.nextLong();
                if (x == 0) cnt0++;
                else if (x == 1) cnt1++;
                else if (x == -1) cntm1++;
                else cntBig++;
            }
            boolean ok = true;
            if (cntBig > 1) ok = false;
            else if (cntBig == 1 && cntm1 > 0) ok = false;
            else if (cntm1 > 1 && cnt1 == 0) ok = false;
            sb.append(ok ? 1 : 0).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

