#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        cnt0 = cnt1 = cntm1 = cntBig = 0
        for _ in range(N):
            x = int(next(it))
            if x == 0:
                cnt0 += 1
            elif x == 1:
                cnt1 += 1
            elif x == -1:
                cntm1 += 1
            else:
                cntBig += 1
        ok = True
        if cntBig > 1:
            ok = False
        elif cntBig == 1 and cntm1 > 0:
            ok = False
        elif cntm1 > 1 and cnt1 == 0:
            ok = False
        out.append('1' if ok else '0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

